import { Auth } from '../core/auth.js';
import { API } from '../core/api.js';
import { AppState } from './dashboard.js';
import { Notifications } from '../ui/notifications.js';
import { Skeletons } from '../ui/skeletons.js';
import { Dashboard } from './dashboard.js';

const Profile = (() => {
   let isEditMode = false;
   let localProfile = null;
   let doctorProfile = null;

   async function load() {
      const { user } = AppState;
      if (!user) return;

      Skeletons.render('dashboardContent', 1);

      const { data, success } = await API.getStaffProfile(AppState.role, user.id);
      if (success) localProfile = { ...data };

      if (AppState.role === 'doctor') {
         const dp = await API.getDoctorProfile(user.id);
         if (dp.success) doctorProfile = dp.data;
      }

      renderMain();
   }

   function renderMain() {
      const content = document.getElementById('dashboardContent');
      if (!content) return;

      const profileName = localProfile?.full_name || AppState.user?.email?.split('@')[0] || 'Doctor';
      const department = doctorProfile?.department || localProfile?.department || '--';
      const spec = doctorProfile?.specialization || localProfile?.specialization || 'General Practice';

      content.innerHTML = `
      <div class="profile-container fade-in">
        <div class="profile-header-card glass-card p-8 mb-6 rounded-[32px]">
          <div class="flex items-center gap-8">
            <div class="profile-avatar-large w-[120px] h-[120px] bg-gradient-to-br from-indigo-500 to-purple-600 rounded-full flex items-center justify-center text-[3.5rem] font-black text-white border-4 border-white/10 relative overflow-hidden">
                ${profileName[0]}
            </div>
            <div class="profile-title flex-1">
               <h2 class="text-4xl font-black text-white tracking-tighter mb-2">${profileName}</h2>
               <div class="flex gap-3">
                 <span class="px-4 py-1.5 rounded-full bg-indigo-500/20 text-indigo-300 text-xs font-bold border border-indigo-500/30">${spec}</span>
                 <span class="px-4 py-1.5 rounded-full bg-white/5 text-slate-400 text-xs font-bold border border-white/10">${department}</span>
               </div>
               <div class="mt-3 text-xs opacity-50">Member since ${new Date(localProfile?.created_at || Date.now()).toLocaleDateString()}</div>
            </div>
            <div class="profile-actions-header flex gap-2">
               <button class="btn btn-secondary px-6 py-3 rounded-xl font-bold" onclick="Profile.toggleEdit()">
                  ${isEditMode ? 'Cancel' : 'Edit Profile'}
               </button>
               ${isEditMode ? `<button class="btn btn-primary px-6 py-3 rounded-xl font-bold" onclick="Profile.handleSave()">Save Changes</button>` : ''}
               <button id="logoutBtn" class="logout-btn font-bold ml-2" onclick="Profile.logout()">Logout</button>
            </div>
          </div>
        </div>

        <div class="grid grid-cols-1 lg:grid-cols-2 gap-6">
          <div class="glass-card p-8 rounded-[28px]">
            <h3 class="text-xl font-black text-white mb-6 flex items-center gap-3">
                Professional Credentials
            </h3>
            <div class="flex flex-col gap-6">
               <div class="grid grid-cols-2 gap-4">
                   <div>
                      <label class="block text-[0.7rem] font-black text-slate-500 uppercase tracking-widest mb-2">Full Name</label>
                      <input type="text" id="profileName" class="form-input" value="${profileName}" ${!isEditMode ? 'disabled' : ''}>
                   </div>
                   <div>
                      <label class="block text-[0.7rem] font-black text-slate-500 uppercase tracking-widest mb-2">Phone</label>
                      <input type="text" id="profilePhone" class="form-input" value="${localProfile?.phone || ''}" ${!isEditMode ? 'disabled' : ''}>
                   </div>
               </div>
               <div class="grid grid-cols-2 gap-4">
                   <div>
                      <label class="block text-[0.7rem] font-black text-slate-500 uppercase tracking-widest mb-2">Department</label>
                      <input type="text" id="profileDepartment" class="form-input" value="${department}" ${!isEditMode ? 'disabled' : ''}>
                   </div>
                   <div>
                      <label class="block text-[0.7rem] font-black text-slate-500 uppercase tracking-widest mb-2">Specialization</label>
                      <input type="text" id="profileSpecialization" class="form-input" value="${spec}" ${!isEditMode ? 'disabled' : ''}>
                   </div>
               </div>
               <div class="grid grid-cols-2 gap-4">
                   <div>
                      <label class="block text-[0.7rem] font-black text-slate-500 uppercase tracking-widest mb-2">Experience (Years)</label>
                      <input type="number" id="profileExperience" class="form-input" value="${doctorProfile?.experience_years || 0}" ${!isEditMode ? 'disabled' : ''}>
                   </div>
                   <div>
                      <label class="block text-[0.7rem] font-black text-slate-500 uppercase tracking-widest mb-2">Working Schedule</label>
                      <input type="text" id="workingSchedule" class="form-input" placeholder="e.g. 8AM - 4PM" value="${doctorProfile?.working_schedule || ''}" ${!isEditMode ? 'disabled' : ''}>
                   </div>
               </div>
            </div>
          </div>

          <div class="flex flex-col gap-6">
              <div class="glass-card p-8 rounded-[28px] h-full">
                <h3 class="text-xl font-black text-white mb-6">Status & Availability</h3>
                <div class="flex flex-col gap-6">
                     <div>
                        <label class="block text-[0.7rem] font-black text-slate-500 uppercase tracking-widest mb-2">Clinical Availability</label>
                        <button class="w-full p-4 rounded-2xl font-black transition-all ${localProfile?.status === 'on-duty' ? 'bg-emerald-500/20 text-emerald-400 border border-emerald-500/30' : 'bg-white/5 text-slate-400 border border-white/10'}" onclick="Profile.toggleStatus()" ${!isEditMode ? 'disabled' : ''}>
                           ${localProfile?.status === 'on-duty' ? 'On Duty' : 'Off Duty'}
                        </button>
                     </div>
                </div>
              </div>
          </div>
        </div>

        ${(doctorProfile?.bio || isEditMode) ? `
          <div class="glass-card p-8 rounded-[28px] mt-6">
            <h3 class="text-xl font-black text-white mb-4">Biography</h3>
            ${isEditMode ?
               `<textarea id="editBio" class="form-input w-full p-4 rounded-2xl" rows="4">${doctorProfile?.bio || ''}</textarea>` :
               `<p class="text-slate-400 leading-relaxed">${doctorProfile?.bio || 'No bio provided.'}</p>`}
          </div>` : ''}
      </div>
    `;
   }

   function toggleEdit() {
      isEditMode = !isEditMode;
      renderMain();
   }

   async function handleSave() {
      const staffUpdates = {
         full_name: document.getElementById('profileName').value,
         phone: document.getElementById('profilePhone').value,
         department: document.getElementById('profileDepartment').value,
         specialization: document.getElementById('profileSpecialization').value
      };

      const doctorUpdates = {
         name: staffUpdates.full_name,
         phone: staffUpdates.phone,
         department: staffUpdates.department,
         specialization: staffUpdates.specialization,
         experience_years: parseInt(document.getElementById('profileExperience').value || 0),
         working_schedule: document.getElementById('workingSchedule').value || ''
      };

      Notifications.info('Clinical credentials being synchronized...');

      const { success: staffSuccess } = await API.updateStaffProfile(AppState.role, AppState.user.id, staffUpdates);

      if (AppState.role === 'doctor') {
         await API.updateDoctorProfile(AppState.user.id, doctorUpdates);
         doctorProfile = { ...doctorProfile, ...doctorUpdates };
      }

      if (staffSuccess) {
         localProfile = { ...localProfile, ...staffUpdates };
         isEditMode = false;
         renderMain();
         Notifications.success('Clinical profile updated successfully.');
         Dashboard.updateHeader();
      }
   }

   async function toggleStatus() {
      const newStatus = localProfile?.status === 'on-duty' ? 'off-duty' : 'on-duty';
      const { success } = await API.updateStaffProfile(AppState.role, AppState.user.id, { status: newStatus });
      if (success) {
         localProfile.status = newStatus;
         renderMain();
         Dashboard.updateHeader();
      }
   }

   async function logout() {
      try {
         Notifications.info('Terminating secure clinical session...');
         await Auth.signOut();
         sessionStorage.removeItem("demoMode");
         window.location.href = "/index.html";
      } catch (err) {
         console.error('Logout failed:', err);
         sessionStorage.removeItem("demoMode");
         window.location.href = "/index.html";
      }
   }

   return { load, toggleEdit, handleSave, toggleStatus, logout };
})();

export { Profile };
window.Profile = Profile;


